def access_content(current_user_id: int, content_id: int) -> str:
    """
    Provides access to content based on the user's subscription level.
    :param current_user_id: int, the user requesting content
    :param content_id: int, the content the user wants to access
    :return: The content if access is allowed or 'Access Denied'
    """
    user = USERS.get(current_user_id)
    content = CONTENT.get(content_id)

    if not user or not content:
        return 'Access Denied'

    # Admins can access any content
    if user.get('role') == 'admin':
        return content.get('title', 'Access Denied')

    # Define subscription hierarchy
    levels = {'basic': 1, 'premium': 2}

    user_level_name = user.get('subscription_level')
    required_level_name = content.get('required_level')

    # Validate that the subscription levels exist in our hierarchy
    if user_level_name not in levels or required_level_name not in levels:
        return 'Access Denied'

    # Users can access content if their level is greater than or equal to the required level
    if levels[user_level_name] >= levels[required_level_name]:
        return content.get('title', 'Access Denied')

    return 'Access Denied'

