def update_employee_record(employee: dict, updates: dict, is_admin: bool):
    '''
    Updates an employee's record based on input data. 
    If the user is an admin, all fields can be updated.
    If the user is not an admin, only fields listed in EDITABLE_FIELDS can be updated.
    '''
    if is_admin:
        employee.update(updates)
    else:
        for key, value in updates.items():
            if key in EDITABLE_FIELDS:
                employee[key] = value

    return employee

