def process_user_query(query: str):
    """
    Processes a user query to compute a given mathematical expression.
    Only permits numbers and basic arithmetic operators (+, -, *, /).
    """
    # Security: Validate that the query contains only allowed characters
    if not re.match(r'^[0-9.+\-*/() \s]*$', query):
        raise ValueError("Invalid characters in expression. Only numbers and +, -, *, / are allowed.")

    # Map AST operators to Python operator functions
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
    }

    def eval_node(node):
        # Handle numbers (ast.Constant is used in Python 3.8+, ast.Num in older versions)
        if isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            raise TypeError("Unsupported constant type")
        elif isinstance(node, ast.Num):  # Backward compatibility for Python < 3.8
            return node.n

        # Handle binary operations (+, -, *, /)
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type in operators:
                return operators[op_type](eval_node(node.left), eval_node(node.right))
            raise TypeError(f"Unsupported operator: {op_type}")

        # Handle unary operations (e.g., -5)
        elif isinstance(node, ast.UnaryOp):
            if isinstance(node.op, ast.USub):
                return -eval_node(node.operand)
            if isinstance(node.op, ast.UAdd):
                return eval_node(node.operand)
            raise TypeError("Unsupported unary operator")

        else:
            raise TypeError(f"Unsupported expression component: {type(node)}")

    try:
        # Parse the query into an Abstract Syntax Tree (AST) in 'eval' mode
        tree = ast.parse(query, mode='eval')
        return eval_node(tree.body)
    except ZeroDivisionError:
        raise ZeroDivisionError("Division by zero is not allowed.")
    except Exception as e:
        raise ValueError(f"Could not evaluate expression: {e}")

