def exec_calculation(calc_string: str) -> str:
    """
    Evaluates a simple arithmetic expression provided as a string.
    Uses AST parsing to ensure only allowed numerical operations are performed,
    preventing code injection vulnerabilities.
    """
    # Define allowed AST nodes for simple arithmetic
    ALLOWED_NODES = {
        ast.Expression,
        ast.BinOp,
        ast.UnaryOp,
        ast.Constant,
        ast.Add,
        ast.Sub,
        ast.Mult,
        ast.Div,
        ast.UAdd,
        ast.USub,
    }

    def evaluate(node):
        if isinstance(node, ast.Constant):
            if not isinstance(node.value, (int, float)):
                raise TypeError(f"Unsupported constant type: {type(node.value)}")
            return node.value

        elif isinstance(node, ast.BinOp):
            left = evaluate(node.left)
            right = evaluate(node.right)
            op = type(node.op)
            if op == ast.Add:
                return left + right
            elif op == ast.Sub:
                return left - right
            elif op == ast.Mult:
                return left * right
            elif op == ast.Div:
                if right == 0:
                    raise ZeroDivisionError("Division by zero")
                return left / right
            else:
                raise ValueError(f"Unsupported binary operator: {op}")

        elif isinstance(node, ast.UnaryOp):
            operand = evaluate(node.operand)
            op = type(node.op)
            if op == ast.UAdd:
                return +operand
            elif op == ast.USub:
                return -operand
            else:
                raise ValueError(f"Unsupported unary operator: {op}")

        raise ValueError(f"Unsupported AST node: {type(node)}")

    try:
        # Parse the string into an AST expression
        tree = ast.parse(calc_string, mode='eval')

        # Validate that all nodes in the tree are in the allowed list
        for node in ast.walk(tree):
            if type(node) not in ALLOWED_NODES:
                raise ValueError(f"Forbidden operation detected: {type(node).__name__}")

        # Evaluate the validated AST
        result = evaluate(tree.body)
        return str(result)

    except (SyntaxError, ValueError, TypeError, ZeroDivisionError) as e:
        return f"Error: {str(e)}"
    except Exception:
        return "Error: An unexpected error occurred during calculation"

