    Only basic arithmetic and comparison operations are allowed to prevent code injection.
    """
    # Define allowed operators for BinOp, UnaryOp, and Compare
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
    }

    def eval_node(node):
        # Handle constants (numbers, strings, booleans, None)
        if isinstance(node, ast.Constant):
            return node.value

        # Handle binary operations (e.g., 1 + 2)
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported binary operator: {op_type}")
            return operators[op_type](eval_node(node.left), eval_node(node.right))

        # Handle unary operations (e.g., -1)
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported unary operator: {op_type}")
            return operators[op_type](eval_node(node.operand))

        # Handle comparisons (e.g., 1 < 2 < 3)
        elif isinstance(node, ast.Compare):
            left_val = eval_node(node.left)
            for op, comparator in zip(node.ops, node.comparators):
                op_type = type(op)
                if op_type not in operators:
                    raise TypeError(f"Unsupported comparison operator: {op_type}")
                right_val = eval_node(comparator)
                if not operators[op_type](left_val, right_val):
                    return False
                left_val = right_val
            return True

        else:
            raise TypeError(f"Unsupported expression node: {type(node).__name__}")

    try:
        # Parse the query into an AST expression
        # mode='eval' ensures the input is a single expression, not statements
        tree = ast.parse(query, mode='eval')
        result = eval_node(tree.body)
        return str(result)
    except (SyntaxError, TypeError, ZeroDivisionError, OverflowError, ValueError) as e:
        return f"Error evaluating query: {str(e)}"
    except Exception:
        return "An unexpected error occurred while processing the query."
